java-study/dynamicdatasource-shi-xian-sh.body:
dynamic-datasource实现数据读写分离
背景
随着业务流量越来越大，所有数据库请求都访问mysql主库，给主库造成了较大的压力
目标
减轻mysql主库压力
现状
当前数据库部署架构为一主一从，从库只是单纯作为备份，没有承接线上流量，资源有闲置
方案
方案对比
通常会有其中思路
分库
分库的思路是讲数据库中表根据业务紧密程度拆分成几个不同的库，不同的表访问不同的库，不同的库分布在不同的节点，从而可以减轻单个库的压力，是一种横向扩展的思路，类似的还有分表，这里不做介绍
分库通常会涉及到系统的改造，比如原先在一个库的表，一个事务就可以保证，拆分成多个库之后，原先一个事务可以完成的，现在不能保证正确，通常涉及到分布式事务或者BASE等，改造成本比较高
读写分离
读写分离也是业界常用的方案之一，思路是在数据库主从同步延迟可以接受的范围内，讲一部分查询请求分流到数据库从库，从来降低主库压力
考虑到目前的数据容量以及改造成本，现阶段先采用读写分离的方式
实施
因为系统已经集成了dynamic-datasource介入了多个不同的数据源，因此方案基于此作
先了解下dynamic-datasource核心类
首先是com.baomidou.dynamic.datasource.spring.boot.autoconfigure.DynamicDataSourceAutoConfiguration
@Slf4j
@Configuration
@EnableConfigurationProperties(DynamicDataSourceProperties.class)
@AutoConfigureBefore(value = DataSourceAutoConfiguration.class, name = "com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure")
@Import(value = {DruidDynamicDataSourceConfiguration.class, DynamicDataSourceCreatorAutoConfiguration.class})
@ConditionalOnProperty(prefix = DynamicDataSourceProperties.PREFIX, name = "enabled", havingValue = "true", matchIfMissing = true)
public class DynamicDataSourceAutoConfiguration implements InitializingBean {

    private final DynamicDataSourceProperties properties;

    private final List dataSourcePropertiesCustomizers;

    public DynamicDataSourceAutoConfiguration(
            DynamicDataSourceProperties properties,
            ObjectProvider> dataSourcePropertiesCustomizers) {
        this.properties = properties;
        this.dataSourcePropertiesCustomizers = dataSourcePropertiesCustomizers.getIfAvailable();
    }

    @Bean
    public DynamicDataSourceProvider ymlDynamicDataSourceProvider() {
        return new YmlDynamicDataSourceProvider(properties.getDatasource());
    }

    @Bean
    @ConditionalOnMissingBean
    public DataSource dataSource() {
        DynamicRoutingDataSource dataSource = new DynamicRoutingDataSource();
        dataSource.setPrimary(properties.getPrimary());
        dataSource.setStrict(properties.getStrict());
        dataSource.setStrategy(properties.getStrategy());
        dataSource.setP6spy(properties.getP6spy());
        dataSource.setSeata(properties.getSeata());
        return dataSource;
    }

    @Role(BeanDefinition.ROLE_INFRASTRUCTURE)
    @Bean
    @ConditionalOnProperty(prefix = DynamicDataSourceProperties.PREFIX + ".aop", name = "enabled", havingValue = "true", matchIfMissing = true)
    public Advisor dynamicDatasourceAnnotationAdvisor(DsProcessor dsProcessor) {
        DynamicDatasourceAopProperties aopProperties = properties.getAop();
        DynamicDataSourceAnnotationInterceptor interceptor = new DynamicDataSourceAnnotationInterceptor(aopProperties.getAllowedPublicOnly(), dsProcessor);
        DynamicDataSourceAnnotationAdvisor advisor = new DynamicDataSourceAnnotationAdvisor(interceptor, DS.class);
        advisor.setOrder(aopProperties.getOrder());
        return advisor;
    }

    // ...

    @Bean
    @ConditionalOnMissingBean
    public DsProcessor dsProcessor(BeanFactory beanFactory) {
        DsHeaderProcessor headerProcessor = new DsHeaderProcessor();
        DsSessionProcessor sessionProcessor = new DsSessionProcessor();
        DsSpelExpressionProcessor spelExpressionProcessor = new DsSpelExpressionProcessor();
        spelExpressionProcessor.setBeanResolver(new BeanFactoryResolver(beanFactory));
        headerProcessor.setNextProcessor(sessionProcessor);
        sessionProcessor.setNextProcessor(spelExpressionProcessor);
        return headerProcessor;
    }

    // ...
}

该Configuration定义了几个bean

ymlDynamicDataSourceProvider，用于创建实际的数据库如druid/c3p等，代码比较简单这里忽略
dataSource，实际类型是DynamicRoutingDataSource，是对众多dataSource的封装，接下来会细讲
dynamicDatasourceAnnotationAdvisor，主要功能就是解析接口或者方法上的@DS注解并将值并放入线程上下文（DynamicDataSourceContextHolder）中

接下来看DynamicRoutingDataSource类
先看afterPropertiesSet
@Override
public void afterPropertiesSet() throws Exception {
    // 检查开启了配置但没有相关依赖
    checkEnv();
    // 添加并分组数据源
    Map dataSources = new HashMap<>(16);
    for (DynamicDataSourceProvider provider : providers) {
        dataSources.putAll(provider.loadDataSources());
    }
    for (Map.Entry dsItem : dataSources.entrySet()) {
        addDataSource(dsItem.getKey(), dsItem.getValue());
    }
    // 检测默认数据源是否设置
    if (groupDataSources.containsKey(primary)) {
        log.info("dynamic-datasource initial loaded [{}] datasource,primary group datasource named [{}]", dataSources.size(), primary);
    } else if (dataSourceMap.containsKey(primary)) {
        log.info("dynamic-datasource initial loaded [{}] datasource,primary datasource named [{}]", dataSources.size(), primary);
    } else {
        log.warn("dynamic-datasource initial loaded [{}] datasource,Please add your primary datasource or check your configuration", dataSources.size());
    }
}

主要是讲所有的实际数据库连接放到两个map

Map\，最简单的分组，key是配置的数据库name，value是具体的数据库
Map\，将配置的数据库name按照下划线分割之后，取第一个分组

代码如下
/**
 * 添加数据源
 *
 * @param ds         数据源名称
 * @param dataSource 数据源
 */
public synchronized void addDataSource(String ds, DataSource dataSource) {
    DataSource oldDataSource = dataSourceMap.put(ds, dataSource);
    // 新数据源添加到分组
    this.addGroupDataSource(ds, dataSource);
    // 关闭老的数据源
    if (oldDataSource != null) {
        closeDataSource(ds, oldDataSource);
    }
    log.info("dynamic-datasource - add a datasource named [{}] success", ds);
}

/**
 * 新数据源添加到分组
 *
 * @param ds         新数据源的名字
 * @param dataSource 新数据源
 */
private void addGroupDataSource(String ds, DataSource dataSource) {
    if (ds.contains(UNDERLINE)) {
        String group = ds.split(UNDERLINE)[0];
        GroupDataSource groupDataSource = groupDataSources.get(group);
        if (groupDataSource == null) {
            try {
                groupDataSource = new GroupDataSource(group, strategy.getDeclaredConstructor().newInstance());
                groupDataSources.put(group, groupDataSource);
            } catch (Exception e) {
                throw new RuntimeException("dynamic-datasource - add the datasource named " + ds + " error", e);
            }
        }
        groupDataSource.addDatasource(ds, dataSource);
    }
}

接下来看下AbstractRoutingDataSource，是DynamicRoutingDataSource的基类
public abstract class AbstractRoutingDataSource extends AbstractDataSource {

    /**
     * 抽象获取连接池
     *
     * @return 连接池
     */
    protected abstract DataSource determineDataSource();

    @Override
    public Connection getConnection() throws SQLException {
        String xid = TransactionContext.getXID();
        if (StringUtils.isEmpty(xid)) {
            return determineDataSource().getConnection();
        } else {
            String ds = DynamicDataSourceContextHolder.peek();
            ds = StringUtils.isEmpty(ds) ? "default" : ds;
            ConnectionProxy connection = ConnectionFactory.getConnection(ds);
            return connection == null ? getConnectionProxy(ds, determineDataSource().getConnection()) : connection;
        }
    }

    @Override
    public Connection getConnection(String username, String password) throws SQLException {
        String xid = TransactionContext.getXID();
        if (StringUtils.isEmpty(xid)) {
            return determineDataSource().getConnection(username, password);
        } else {
            String ds = DynamicDataSourceContextHolder.peek();
            ds = StringUtils.isEmpty(ds) ? "default" : ds;
            ConnectionProxy connection = ConnectionFactory.getConnection(ds);
            return connection == null ? getConnectionProxy(ds, determineDataSource().getConnection(username, password))
                    : connection;
        }
    }
    // ...
}

getConnection方法可以看到动态切换数据的逻辑，具体逻辑留给了子类实现即determineDataSource方法
接下来，我们DynamicDataSourceAutoConfiguration.determineDataSource方法
@Override
public DataSource determineDataSource() {
    String dsKey = DynamicDataSourceContextHolder.peek();
    return getDataSource(dsKey);
}

/**
 * 获取数据源
 *
 * @param ds 数据源名称
 * @return 数据源
 */
public DataSource getDataSource(String ds) {
    if (StringUtils.isEmpty(ds)) {
        return determinePrimaryDataSource();
    } else if (!groupDataSources.isEmpty() && groupDataSources.containsKey(ds)) {
        log.debug("dynamic-datasource switch to the datasource named [{}]", ds);
        return groupDataSources.get(ds).determineDataSource();
    } else if (dataSourceMap.containsKey(ds)) {
        log.debug("dynamic-datasource switch to the datasource named [{}]", ds);
        return dataSourceMap.get(ds);
    }
    if (strict) {
        throw new CannotFindDataSourceException("dynamic-datasource could not find a datasource named" + ds);
    }
    return determinePrimaryDataSource();
}

private DataSource determinePrimaryDataSource() {
    log.debug("dynamic-datasource switch to the primary datasource");
    DataSource dataSource = dataSourceMap.get(primary);
    if (dataSource != null) {
        return dataSource;
    }
    GroupDataSource groupDataSource = groupDataSources.get(primary);
    if (groupDataSource != null) {
        return groupDataSource.determineDataSource();
    }
    throw new CannotFindDataSourceException("dynamic-datasource can not find primary datasource");
}

可以发现，如果从上下文可以获取到ds，将根据ds选择数据库，如果没有ds，将直接根据配置的primary选择数据库
还记得上文中提到的两个map吗，可以发现如果ds命中第一map时，返回的数据库是固定的，也就无法实现所谓的读写分离；除非每个方法都手动通过@DS注解指定，这种方式不友好；当第一个map不命中且第二个map命中时，实现轻松在多个数据库之间动态切换，且不需要在方法上指定@DS注解
因此第一个关键点就是要对 数据库进行分组，配置方式如下
spring:
  datasource:
    dynamic:
      datasource:
        group1_master:
          # 具体数据库配置
        group1_slave1:
          # 具体数据库配置
        group1_slave2:
          # 具体数据库配置
        group2_master:
          # 具体数据库配置
        group2_slave1:
          # 具体数据库配置
        group2_slave2:
          # 具体数据库配置

如果走到分组，具体分组逻辑是GroupDataSource.determineDataSource方法
public String determineDsKey() {
    return dynamicDataSourceStrategy.determineKey(new ArrayList<>(dataSourceMap.keySet()));
}

public DataSource determineDataSource() {
    return dataSourceMap.get(determineDsKey());
}

可以看到，具体选择分组中的那个数据库，是根据dynamicDataSourceStrategy来决定的，因此我们只需要实现一个dynamicDataSourceStrategy的实现能够根据读写请求选择不同的ds即可。
策略基本如下：
1、普通读请求，走从库或者主库都可以
2、普通写请求，走主库
3、强制指定了走主库的请求，走主库
4、事务执行，强制走主库
接下来难点在于
1、如何判断是读请求还是写请求
2、如何判断强制走主库
3、对于事物，比较特殊，在事务开启之前就需要切到主库然后获取数据库连接
一个一个解决
首先判断是否读请求还是写请求，这个需要使用mybatis拦截器，拦截Executor方法
public interface Executor {
    ResultHandler NO_RESULT_HANDLER = null;

    int update(MappedStatement var1, Object var2) throws SQLException;

     List query(MappedStatement var1, Object var2, RowBounds var3, ResultHandler var4, CacheKey var5, BoundSql var6) throws SQLException;

     List query(MappedStatement var1, Object var2, RowBounds var3, ResultHandler var4) throws SQLException;
   // ...
}

通过第一个参数MappedStatement可以判断
SqlCommandType.SELECT == MappedStatement.getSqlCommandType()

接下来就是如何判断强制走主库了，这个需要自定义实现，通常是使用注解+AOP方式
所以整体实现比较简单
首先定义上下文，保存是否走主库标志
public class ForceMasterContext {

    private static final ThreadLocal FORCE_MASTER = new ThreadLocal<>();

    public static void setForceMaster(boolean forceMaster) {
        FORCE_MASTER.set(forceMaster);
    }

    public static boolean isForceMaster() {
        return FORCE_MASTER.get() != null && FORCE_MASTER.get();
    }

    public static void clearForceMaster() {
        FORCE_MASTER.remove();
    }
}

接下来实现策略，根据标志位选择主库或者从库
@Slf4j
public class ForceMasterDynamicDataSourceStrategy extends LoadBalanceDynamicDataSourceStrategy {

    private static final String MASTER_SUFFIX = "_master";

    @Override
    public String determineKey(List dsNames) {
        String ds = null;
        if (ForceMasterContext.isForceMaster()) {
            ds = Optional.ofNullable(dsNames)
                    .orElse(new ArrayList<>())
                    .stream()
                    .filter(StringUtils::isNotBlank)
                    .filter(o -> o.endsWith(MASTER_SUFFIX))
                    .findFirst()
                    .orElse(null);
        }

        if (ds == null) {
            ds = super.determineKey(dsNames);
        }

        return ds;
    }
}

需要修改配置，指定spring.datasource.dynamic.strategy=Xxx.class才会生效
定义mybatis拦截器，设置
@Intercepts({@Signature(
        type = Executor.class,
        method = "query",
        args = {MappedStatement.class, Object.class, RowBounds.class, ResultHandler.class}
), @Signature(
        type = Executor.class,
        method = "query",
        args = {MappedStatement.class, Object.class, RowBounds.class, ResultHandler.class, CacheKey.class, BoundSql.class}
), @Signature(
        type = Executor.class,
        method = "update",
        args = {MappedStatement.class, Object.class}
)})
@Slf4j
@Component
public class ForceMasterPlugin implements Interceptor {

    @Override
    public Object intercept(Invocation invocation) throws Throwable {
        // 事务操作，正常不应该走到这里
        if (TransactionSynchronizationManager.isSynchronizationActive()) {
            return invocation.proceed();
        }

        // 已经强制走到主库了
        if (ForceMasterContext.isForceMaster()) {
            return invocation.proceed();
        }

        Object[] args = invocation.getArgs();
        MappedStatement ms = (MappedStatement) args[0];
        // 非事务中的查询操作直接返回
        if (SqlCommandType.SELECT == ms.getSqlCommandType()) {
            return invocation.proceed();
        }

        try {
            ForceMasterContext.setForceMaster(true);
            return invocation.proceed();
        } finally {
            ForceMasterContext.clearForceMaster();
        }
    }

    @Override
    public Object plugin(Object target) {
        return target instanceof Executor ? Plugin.wrap(target, this) : target;
    }

    @Override
    public void setProperties(Properties properties) {
    }
}

接下来自定义强制走主库注解
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Documented
public @interface ForceMaster {
}

定义Aop
@Configuration
@Aspect
@Slf4j
public class ForceMasterAspectConfiguration {

    @Role(BeanDefinition.ROLE_INFRASTRUCTURE)
    @Bean
    public Advisor forceMasterAdvisor() {
        MethodInterceptor interceptor = invocation -> {
            if (ForceMasterContext.isForceMaster()) {
                return invocation.proceed();
            }

            try {
                ForceMasterContext.setForceMaster(true);
                return invocation.proceed();
            } finally {
                ForceMasterContext.clearForceMaster();
            }
        };
        return new DynamicDataSourceAnnotationAdvisor(interceptor, ForceMaster.class);
    }
}

最后如何判断事务即将开启，spring-tx开启事务在AbstractPlatformTransactionManager.getTransaction方法，代码如下
@Override
public final TransactionStatus getTransaction(@Nullable TransactionDefinition definition)
        throws TransactionException {

    // Use defaults if no transaction definition given.
    TransactionDefinition def = (definition != null ? definition : TransactionDefinition.withDefaults());

    Object transaction = doGetTransaction();
    boolean debugEnabled = logger.isDebugEnabled();

    if (isExistingTransaction(transaction)) {
        // Existing transaction found -> check propagation behavior to find out how to behave.
        return handleExistingTransaction(def, transaction, debugEnabled);
    }

    // Check definition settings for new transaction.
    if (def.getTimeout()  check propagation behavior to find out how to proceed.
    if (def.getPropagationBehavior() == TransactionDefinition.PROPAGATION_MANDATORY) {
        throw new IllegalTransactionStateException(
                "No existing transaction found for transaction marked with propagation 'mandatory'");
    }
    else if (def.getPropagationBehavior() == TransactionDefinition.PROPAGATION_REQUIRED ||
            def.getPropagationBehavior() == TransactionDefinition.PROPAGATION_REQUIRES_NEW ||
            def.getPropagationBehavior() == TransactionDefinition.PROPAGATION_NESTED) {
        SuspendedResourcesHolder suspendedResources = suspend(null);
        if (debugEnabled) {
            logger.debug("Creating new transaction with name [" + def.getName() + "]: " + def);
        }
        try {
            return startTransaction(def, transaction, debugEnabled, suspendedResources);
        }
        catch (RuntimeException | Error ex) {
            resume(null, suspendedResources);
            throw ex;
        }
    }
    else {
        // Create "empty" transaction: no actual transaction, but potentially synchronization.
        if (def.getIsolationLevel() != TransactionDefinition.ISOLATION_DEFAULT && logger.isWarnEnabled()) {
            logger.warn("Custom isolation level specified but no actual transaction initiated; " +
                    "isolation level will effectively be ignored: " + def);
        }
        boolean newSynchronization = (getTransactionSynchronization() == SYNCHRONIZATION_ALWAYS);
        return prepareTransactionStatus(def, null, true, newSynchronization, debugEnabled, null);
    }
}

/**
 * Start a new transaction.
 */
private TransactionStatus startTransaction(TransactionDefinition definition, Object transaction,
        boolean debugEnabled, @Nullable SuspendedResourcesHolder suspendedResources) {

    boolean newSynchronization = (getTransactionSynchronization() != SYNCHRONIZATION_NEVER);
    DefaultTransactionStatus status = newTransactionStatus(
            definition, transaction, true, newSynchronization, debugEnabled, suspendedResources);
    doBegin(transaction, definition);
    prepareSynchronization(status, definition);
    return status;
}

最终会走到doBegin方法，具体实现类在DataSourceTransactionManager中
protected void doBegin(Object transaction, TransactionDefinition definition) {
    DataSourceTransactionManager.DataSourceTransactionObject txObject = (DataSourceTransactionManager.DataSourceTransactionObject)transaction;
    Connection con = null;

    try {
        if (!txObject.hasConnectionHolder() || txObject.getConnectionHolder().isSynchronizedWithTransaction()) {
            Connection newCon = this.obtainDataSource().getConnection();
            if (this.logger.isDebugEnabled()) {
                this.logger.debug("Acquired Connection [" + newCon + "] for JDBC transaction");
            }

            txObject.setConnectionHolder(new ConnectionHolder(newCon), true);
        }

        txObject.getConnectionHolder().setSynchronizedWithTransaction(true);
        con = txObject.getConnectionHolder().getConnection();
        Integer previousIsolationLevel = DataSourceUtils.prepareConnectionForTransaction(con, definition);
        txObject.setPreviousIsolationLevel(previousIsolationLevel);
        txObject.setReadOnly(definition.isReadOnly());
        if (con.getAutoCommit()) {
            txObject.setMustRestoreAutoCommit(true);
            if (this.logger.isDebugEnabled()) {
                this.logger.debug("Switching JDBC Connection [" + con + "] to manual commit");
            }

            con.setAutoCommit(false);
        }

        this.prepareTransactionalConnection(con, definition);
        txObject.getConnectionHolder().setTransactionActive(true);
        int timeout = this.determineTimeout(definition);
        if (timeout != -1) {
            txObject.getConnectionHolder().setTimeoutInSeconds(timeout);
        }

        if (txObject.isNewConnectionHolder()) {
            TransactionSynchronizationManager.bindResource(this.obtainDataSource(), txObject.getConnectionHolder());
        }

    } catch (Throwable var7) {
        if (txObject.isNewConnectionHolder()) {
            DataSourceUtils.releaseConnection(con, this.obtainDataSource());
            txObject.setConnectionHolder((ConnectionHolder)null, false);
        }

        throw new CannotCreateTransactionException("Could not open JDBC Connection for transaction", var7);
    }
}

可以看到doBegin方法中获取了数据连接(Connection对象），结合上面的两个方法，可以发现两点
1、在获取数据库连接之前没有任何的回调和埋点，也就是说无法通过添加钩子在做额外逻辑，也不能通过上下文去判断
2、方法要么是protected，要么是final修饰，也就是说不能通过AOP来扩展
因此只剩下一种方法，通过继承去扩展，且需要修改默认的PlatformTransactionManager实现类
代码如下
@Component
public class ForceMasterDataSourceTransactionManager extends DataSourceTransactionManager {

    public ForceMasterDataSourceTransactionManager(DataSource dataSource, ObjectProvider transactionManagerCustomizers) {
        super(dataSource);

        TransactionManagerCustomizers customizers = transactionManagerCustomizers.getIfAvailable();
        if (customizers != null) {
            customizers.customize(this);
        }
    }

    @Override
    protected void doBegin(Object transaction, TransactionDefinition definition) {
        if (!ForceMasterContext.isForceMaster()) {
            ForceMasterContext.setForceMaster(true);
        }

        super.doBegin(transaction, definition);
    }


    @Override
    protected void doCleanupAfterCompletion(Object transaction) {
        try {
            super.doCleanupAfterCompletion(transaction);
        } finally {
            ForceMasterContext.clearForceMaster();
        }
    }
}

java-study/redis-zhu-cong-jia-gou-li-yon.body:
redis主从架构利用lettuce实现读写分离
背景
随着业务流量越来越大，原先所有流量都访问redis主库，给主库造成了很大的压力
目标
在不影响业务的前提下，减轻redis主库压力
现状
当前redis的部署架构是一主一从，从库只是承担了备份的角色，资源有很大的闲置
方案
如果从库也能承担一部分线上流量，那么主库的压力自然就会减轻；方案理论上可行
问题
项目使用的lettuce + spring-boot-starter-data-redis做redis访问
lettuce本身是支持主从模式的访问的，奈何spring-boot-starter-data-redis对于redis哨兵和redis集群模式都有很好的支持，对于主从没有支持
代码分析
入口
org.springframework.boot.autoconfigure.data.redis.RedisAutoConfiguration
@Configuration(
    proxyBeanMethods = false
)
@ConditionalOnClass({RedisOperations.class})
@EnableConfigurationProperties({RedisProperties.class})
@Import({LettuceConnectionConfiguration.class, JedisConnectionConfiguration.class})
public class RedisAutoConfiguration {
    // ...
}

只看上面的import部分，默认会LettuceConnectionConfiguration会生效，接着看下这个文件
@Bean
@ConditionalOnMissingBean(RedisConnectionFactory.class)
LettuceConnectionFactory redisConnectionFactory(
        ObjectProvider builderCustomizers,
        ClientResources clientResources) {
    LettuceClientConfiguration clientConfig = getLettuceClientConfiguration(builderCustomizers, clientResources,
            getProperties().getLettuce().getPool());
    return createLettuceConnectionFactory(clientConfig);
}

private LettuceConnectionFactory createLettuceConnectionFactory(LettuceClientConfiguration clientConfiguration) {
    if (getSentinelConfig() != null) {
        return new LettuceConnectionFactory(getSentinelConfig(), clientConfiguration);
    }
    if (getClusterConfiguration() != null) {
        return new LettuceConnectionFactory(getClusterConfiguration(), clientConfiguration);
    }
    return new LettuceConnectionFactory(getStandaloneConfig(), clientConfiguration);
}

private LettuceClientConfiguration getLettuceClientConfiguration(
        ObjectProvider builderCustomizers,
        ClientResources clientResources, Pool pool) {
    LettuceClientConfigurationBuilder builder = createBuilder(pool);
    applyProperties(builder);
    if (StringUtils.hasText(getProperties().getUrl())) {
        customizeConfigurationFromUrl(builder);
    }
    builder.clientOptions(createClientOptions());
    builder.clientResources(clientResources);
    builderCustomizers.orderedStream().forEach((customizer) -> customizer.customize(builder));
    return builder.build();
}

redisConnectionFactory会创建最终的RedisConnectionFactory，再看createLettuceConnectionFactory方法，可以发现对哨兵(sentinel)和集群(cluster)是天然支持的，具体怎么配置这里先略过
我们再看LettuceConnectionFactory，这里重点关注afterPropertiesSet方法
public void afterPropertiesSet() {
    this.client = this.createClient();
    this.connectionProvider = new LettuceConnectionFactory.ExceptionTranslatingConnectionProvider(this.createConnectionProvider(this.client, LettuceConnection.CODEC));
    this.reactiveConnectionProvider = new LettuceConnectionFactory.ExceptionTranslatingConnectionProvider(this.createConnectionProvider(this.client, LettuceReactiveRedisConnection.CODEC));
    if (this.isClusterAware()) {
        this.clusterCommandExecutor = new ClusterCommandExecutor(new LettuceClusterTopologyProvider((RedisClusterClient)this.client), new LettuceClusterNodeResourceProvider(this.connectionProvider), EXCEPTION_TRANSLATION);
    }

    this.initialized = true;
    if (this.getEagerInitialization() && this.getShareNativeConnection()) {
        this.initConnection();
    }
}

再看下createConnectionProvider方法
private LettuceConnectionProvider createConnectionProvider(AbstractRedisClient client, RedisCodec codec) {
    if (this.pool != null) {
        return new LettucePoolConnectionProvider(this.pool);
    } else {
        LettuceConnectionProvider connectionProvider = this.doCreateConnectionProvider(client, codec);
        return (LettuceConnectionProvider)(this.clientConfiguration instanceof LettucePoolingClientConfiguration ? new LettucePoolingConnectionProvider(connectionProvider, (LettucePoolingClientConfiguration)this.clientConfiguration) : connectionProvider);
    }
}

protected LettuceConnectionProvider doCreateConnectionProvider(AbstractRedisClient client, RedisCodec codec) {
    ReadFrom readFrom = (ReadFrom)this.getClientConfiguration().getReadFrom().orElse((Object)null);
    if (this.isStaticMasterReplicaAware()) {
        List nodes = (List)((RedisStaticMasterReplicaConfiguration)this.configuration).getNodes().stream().map((it) -> {
            return this.createRedisURIAndApplySettings(it.getHostName(), it.getPort());
        }).peek((it) -> {
            it.setDatabase(this.getDatabase());
        }).collect(Collectors.toList());
        return new StaticMasterReplicaConnectionProvider((RedisClient)client, codec, nodes, readFrom);
    } else {
        return (LettuceConnectionProvider)(this.isClusterAware() ? new ClusterConnectionProvider((RedisClusterClient)client, codec, readFrom) : new StandaloneConnectionProvider((RedisClient)client, codec, readFrom));
    }
}

最终会走到最后一行的最后一条语句new StandaloneConnectionProvider((RedisClient)client, codec, readFrom));
再看StandaloneConnectionProvider，重点看getConnection方法
@Override
public > T getConnection(Class connectionType) {

    if (connectionType.equals(StatefulRedisSentinelConnection.class)) {
        return connectionType.cast(client.connectSentinel());
    }

    if (connectionType.equals(StatefulRedisPubSubConnection.class)) {
        return connectionType.cast(client.connectPubSub(codec));
    }

    if (StatefulConnection.class.isAssignableFrom(connectionType)) {

        return connectionType.cast(readFrom.map(it -> this.masterReplicaConnection(redisURISupplier.get(), it))
                .orElseGet(() -> client.connect(codec)));
    }

    throw new UnsupportedOperationException("Connection type " + connectionType + " not supported!");
}

当connectionType=StatefulConnection时，会走到masterReplicaConnection方法
private StatefulRedisConnection masterReplicaConnection(RedisURI redisUri, ReadFrom readFrom) {

    StatefulRedisMasterReplicaConnection connection = MasterReplica.connect(client, codec, redisUri);
    connection.setReadFrom(readFrom);

    return connection;
}

继续往下追，会走到MasterReplica.connectAsyncSentinelOrAutodiscovery方法
private static  CompletableFuture> connectAsyncSentinelOrAutodiscovery(
        RedisClient redisClient, RedisCodec codec, RedisURI redisURI) {

    LettuceAssert.notNull(redisClient, "RedisClient must not be null");
    LettuceAssert.notNull(codec, "RedisCodec must not be null");
    LettuceAssert.notNull(redisURI, "RedisURI must not be null");

    if (isSentinel(redisURI)) {
        return new SentinelConnector<>(redisClient, codec, redisURI).connectAsync();
    }

    return new AutodiscoveryConnector<>(redisClient, codec, redisURI).connectAsync();
}

最终走到AutodiscoveryConnector，重点关注initializeConnection方法
private Mono> initializeConnection(RedisCodec codec,
        Tuple2> connectionAndUri) {

    ReplicaTopologyProvider topologyProvider = new ReplicaTopologyProvider(connectionAndUri.getT2(),
            connectionAndUri.getT1());

    MasterReplicaTopologyRefresh refresh = new MasterReplicaTopologyRefresh(redisClient, topologyProvider);
    MasterReplicaConnectionProvider connectionProvider = new MasterReplicaConnectionProvider<>(redisClient, codec,
            redisURI, (Map) initialConnections);

    Mono> refreshFuture = refresh.getNodes(redisURI);

    return refreshFuture.map(nodes -> {

        EventRecorder.getInstance().record(new MasterReplicaTopologyChangedEvent(redisURI, nodes));

        connectionProvider.setKnownNodes(nodes);

        MasterReplicaChannelWriter channelWriter = new MasterReplicaChannelWriter(connectionProvider,
                redisClient.getResources());

        StatefulRedisMasterReplicaConnectionImpl connection = new StatefulRedisMasterReplicaConnectionImpl<>(
                channelWriter, codec, redisURI.getTimeout());

        connection.setOptions(redisClient.getOptions());

        return connection;
    });
}

可以发现返回的StatefulRedisMasterReplicaConnection对象中，channerWriter是MasterReplicaChannelWriter；重点看write方法，大部分redis操作都走到这个方法
@Override
@SuppressWarnings("unchecked")
public  RedisCommand write(RedisCommand command) {

    LettuceAssert.notNull(command, "Command must not be null");

    if (closed) {
        throw new RedisException("Connection is closed");
    }

    if (isStartTransaction(command.getType())) {
        inTransaction = true;
    }

    Intent intent = inTransaction ? Intent.WRITE : getIntent(command.getType());
    CompletableFuture> future = (CompletableFuture) masterReplicaConnectionProvider
            .getConnectionAsync(intent);

    if (isEndTransaction(command.getType())) {
        inTransaction = false;
    }

    if (isSuccessfullyCompleted(future)) {
        writeCommand(command, future.join(), null);
    } else {
        future.whenComplete((c, t) -> writeCommand(command, c, t));
    }

    return command;
}

重点在CompletableFuture\> future = (CompletableFuture) masterReplicaConnectionProvider .getConnectionAsync(intent);
public CompletableFuture> getConnectionAsync(Intent intent) {

    if (debugEnabled) {
        logger.debug("getConnectionAsync(" + intent + ")");
    }

    if (readFrom != null && intent == Intent.READ) {
        List selection = readFrom.select(new ReadFrom.Nodes() {

            @Override
            public List getNodes() {
                return knownNodes;
            }

            @Override
            public Iterator iterator() {
                return knownNodes.iterator();
            }

        });

        if (selection.isEmpty()) {
            throw new RedisException(String.format("Cannot determine a node to read (Known nodes: %s) with setting %s",
                    knownNodes, readFrom));
        }

        try {

            Flux> connections = Flux.empty();

            for (RedisNodeDescription node : selection) {
                connections = connections.concatWith(Mono.fromFuture(getConnection(node)));
            }

            if (OrderingReadFromAccessor.isOrderSensitive(readFrom) || selection.size() == 1) {
                return connections.filter(StatefulConnection::isOpen).next().switchIfEmpty(connections.next()).toFuture();
            }

            return connections.filter(StatefulConnection::isOpen).collectList().map(it -> {
                int index = ThreadLocalRandom.current().nextInt(it.size());
                return it.get(index);
            }).switchIfEmpty(connections.next()).toFuture();
        } catch (RuntimeException e) {
            throw Exceptions.bubble(e);
        }
    }

    return getConnection(getMaster());
}

其中有一行需要注意；if (readFrom != null && intent == Intent.READ) 块中的内容
可以发现，当遇到读请求且readFrom不为空时，会有选择节点的策略
所以要实现读写分离，我们只需要保证走到这里时，readFrom是从从库选择节点的策略就行
其中内置的ReadFrom.REPLICA_PREFERRED即可满足要求
接下来需要解决的是如何保证走到这里时readFrom不为空，实际上这里无法直接通过配置完成，具体可以看RedisProperties，里面没有定义这个字段，接下来，我们向上回溯可以发现
LettuceConnectionConfiguration.getLettuceClientConfiguration此时可以通过新增LettuceClientConfigurationBuilderCustomizer去设置readFrom，整个推理过程不在描述
因此，我们只需要增加一个LettuceClientConfigurationBuilderCustomizer实现即可
@ConditionalOnProperty(value = "spring.redis.replica-preferred", havingValue = "true")
@Component
@Slf4j
public class RedisPreferredLettuceClientConfigurationBuilderCustomizer implements LettuceClientConfigurationBuilderCustomizer, InitializingBean {

    @Override
    public void customize(LettuceClientConfiguration.LettuceClientConfigurationBuilder clientConfigurationBuilder) {
        log.info("RedisPreferredLettuceClientConfigurationBuilderCustomizer.customize");
        clientConfigurationBuilder.readFrom(ReadFrom.REPLICA_PREFERRED);
    }

    @Override
    public void afterPropertiesSet() throws Exception {
        log.info("RedisPreferredLettuceClientConfigurationBuilderCustomizer inited");
    }
}

java-study/java-filter-xiu-gai-request-n.body:
java filter修改request内容和response内容
背景
最近在做一个开放平台，因为是对外开放的api，所以针对api做了签名和加密机制
请求阶段：原始request body 加密 -> encrypt body -> 签名，放到header
响应阶段：原始response body 加密 -> encrypt body -> 签名，放到header
方案
对于这种通用的http请求处理，最容易想到的就是通过java servlet filter或者spring mvc interceptor来做，具体原理可以参见下图


对于spring mvc interceptor，可以看下接口定义
因为需要针对request做签名验证和解密操作，因此需要对request和response做修改，springmvc中，request body和response body都是基于流(stream)来做的，但是stream只能读取一次；因此我们需要对request和response做一些处理
事实上，springmvc interceptor并不适合此场景，具体可以参考HandlerInterceptor接口定义
public interface HandlerInterceptor {
    default boolean preHandle(HttpServletRequest request, HttpServletResponse response, Object handler) throws Exception {
        return true;
    }

    default void postHandle(HttpServletRequest request, HttpServletResponse response, Object handler, @Nullable ModelAndView modelAndView) throws Exception {
    }

    default void afterCompletion(HttpServletRequest request, HttpServletResponse response, Object handler, @Nullable Exception ex) throws Exception {
    }
}

此处修改request或者response并不会对后续的请求生效，因为HttpServletRequest，HttpServletResponse都未提供对流的修改操作
此时只能选择java servlet filter，我们看下filter接口定义
public interface Filter {
    default void init(FilterConfig filterConfig) throws ServletException {
    }

    void doFilter(ServletRequest var1, ServletResponse var2, FilterChain var3) throws IOException, ServletException;

    default void destroy() {
    }
}

通常我们实现一个filter是流程如下
public class XxxFilter implements Filter {
    @Override
    public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain) throws IOException, ServletException {
        if (!condition) {
            // 错误处理
            // ...
        } else {
            // 继续往下，交给下一个
            chain.doFilter(request, response) 
        }
    }
}

事实上，我们依然无法修改request和reposne的stream对象，但是chain.doFilter时，我们可以传递一个和原始request, response不一样的对象
那么此处的filter流程如下
1、从header读取签名
2、从request读取request body，解密
3、校验签名，签名不通过，直接返回错误
4、构造新的request，request body内容是request body解密后的内容
5、构造新的response
6、根据新的request, resepond，通过chain.doFilter()继续往下执行
7、读取response body部分，并加密
8、生成签名，放入header
9、通过原始reponse，写入response body加密后的内容
整体框架代码如下
public class ApiSignFilter implements Filter {

    @Override
    public void init(FilterConfig filterConfig) throws ServletException {
    }

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain) throws IOException, ServletException {

        HttpServletRequest httpServletRequest = (HttpServletRequest) request;

        // 读取header内容，app_key，签名等内容
        String appKey = httpServletRequest.getHeader(APP_KEY);
        String sign = httpServletRequest.getHeader(AUTHORIZATION_KEY);
        String nonceStr = httpServletRequest.getHeader(NONCE_STR_KEY);
        String timestamp = httpServletRequest.getHeader(TIMESTAMP_KEY);

        // 缺少header，直接返回错误
        if (StringUtils.isBlank(appKey) || StringUtils.isBlank(sign)) {
            noOkResp((HttpServletResponse) response, HttpStatus.UNAUTHORIZED);
            return;
        }

        // 读取body
        String body = null;
        if (httpServletRequest.getContentLength() > 0) {
            body = new String(IOUtils.toByteArray(httpServletRequest.getInputStream()), request.getCharacterEncoding());
        }
        // 根据规则生成签名
        String verifySign = generateSign(httpServletRequest.getRequestURL().toString(), body, nonceStr, timestamp);
        // 校验签名，校验失败直接返回
        if (!StringUtils.equals(sign, verifySign)) {
            noOkResp((HttpServletResponse) response, HttpStatus.UNAUTHORIZED);
            return;
        }

        // 解密request body 
        String postRequestBody = null;
        if (StringUtils.isNotBlank(body)) {
            JSONObject bodyMap = JSON.parseObject(body);
            postRequestBody = clientHelper.decryptBody((String) bodyMap.get(ENCRYPT_BODY_KEY));
        }

        // 构造新的request和response，继续执行请求
        AuthHttpServletRequestWrapper requestWrapper = new AuthHttpServletRequestWrapper(httpServletRequest, postRequestBody);
        AuthHttpServletResponseWrapper responseWrapper = new AuthHttpServletResponseWrapper((HttpServletResponse) response);
        chain.doFilter(requestWrapper, responseWrapper);

        // 请求失败处理
        if (responseWrapper.getStatus() != HttpStatus.OK.value()) {
            response.getOutputStream().write(responseWrapper.getResponseData());
            response.getOutputStream().flush();
            return;
        }

        // 读取body并加密
        String respBody = new String(responseWrapper.getResponseData(), responseWrapper.getCharacterEncoding());
        String encryptRespBody = clientHelper.encryptBody(respBody);

        Map encryptBodyMap = new HashMap<>();
        encryptBodyMap.put(ENCRYPT_BODY_KEY, encryptRespBody);
        String postBody = JSON.toJSONString(encryptBodyMap);

        // 生成签名并写入header
        nonceStr = UUID.randomUUID().toString();
        long respTs = System.currentTimeMillis();
        String responseSign = generateSign(requestWrapper.getRequestURL().toString(), postBody, nonceStr, respTs);
        ((HttpServletResponse) response).addHeader(NONCE_STR_KEY, nonceStr);
        ((HttpServletResponse) response).addHeader(TIMESTAMP_KEY, String.valueOf(respTs));
        ((HttpServletResponse) response).addHeader(AUTHORIZATION_KEY, responseSign);

        // 写入加密后的reseponse body
        response.getWriter().write(postBody);
        response.getWriter().flush();
    }

具体的RequestWrapper，ResponseWrapper代码如下
public class AuthHttpServletRequestWrapper extends HttpServletRequestWrapper {
    /// 这里缓存了body
    private byte[] body;

    public AuthHttpServletRequestWrapper(HttpServletRequest request, String data) {
        super(request);
        body = data == null ? new byte[0] : data.getBytes(StandardCharsets.UTF_8);
    }

    // 这里保证了stream可以多次读取
    @Override
    public ServletInputStream getInputStream() {
        return new RRServletInputStreamWrapper(body);
    }

    @Override
    public BufferedReader getReader() {
        return new BufferedReader(new InputStreamReader(this.getInputStream()));
    }
}

public class RRServletInputStreamWrapper extends ServletInputStream {

    private InputStream inputStream;

    public RRServletInputStreamWrapper(byte[] data) {
        super();
        this.inputStream = new ByteArrayInputStream(data);
    }

    @Override
    public boolean isFinished() {
        return false;
    }

    @Override
    public boolean isReady() {
        return true;
    }

    @Override
    public void setReadListener(ReadListener readListener) {

    }

    @Override
    public int read() throws IOException {
        return this.inputStream.read();
    }
}

public class AuthHttpServletResponseWrapper extends HttpServletResponseWrapper {

    private ByteArrayOutputStream buffer;
    private ServletOutputStream outputStream;
    private PrintWriter writer;

    public AuthHttpServletResponseWrapper(HttpServletResponse response) throws UnsupportedEncodingException {
        super(response);

        this.buffer = new ByteArrayOutputStream();
        // 这里不是原始response可以拿到的outputStream，这里做了缓存，因此写入不会影响到response
        this.outputStream = new BufferedServletOutputStreamWrapper(buffer);
        this.writer = new PrintWriter(new OutputStreamWriter(buffer, this.getCharacterEncoding()));
    }


    @Override
    public ServletOutputStream getOutputStream() throws IOException {
        return this.outputStream;
    }

    @Override
    public PrintWriter getWriter() throws IOException {
        return this.writer;
    }

    @Override
    public void flushBuffer() throws IOException {
        if (outputStream != null) {
            outputStream.flush();
        }
        if (writer != null) {
            writer.flush();
        }
    }

    @Override
    public void reset() {
        buffer.reset();
    }

    public byte[] getResponseData() throws IOException {
        flushBuffer();
        return buffer.toByteArray();
    }
}

public class BufferedServletOutputStreamWrapper extends ServletOutputStream {

    private OutputStream outputStream;

    public BufferedServletOutputStreamWrapper(OutputStream outputStream) {
        super();
        this.outputStream = outputStream;
    }

    @Override
    public boolean isReady() {
        return true;
    }

    @Override
    public void setWriteListener(WriteListener writeListener) {

    }

    @Override
    public void write(int b) throws IOException {
        this.outputStream.write(b);
    }

    @Override
    public void write(byte[] b) throws IOException {
        super.write(b, 0, b.length);
    }
}

